func convertAbortBatchStatement(n *googlesql.ASTAbortBatchStatement) *AbortBatchStatement {
	if n == nil {
		return nil
	}
	start, end := ast.GetParseLocationByteOffsets(n)
	res := &AbortBatchStatement{
		Location: LocationRange{Start: start, End: end},
	}
	return res
}

func convertAddColumnAction(n *googlesql.ASTAddColumnAction) *AddColumnAction {
	if n == nil {
		return nil
	}
	start, end := ast.GetParseLocationByteOffsets(n)
	res := &AddColumnAction{
		Location: LocationRange{Start: start, End: end},
	}
	if val, err := n.ColumnDefinition(); err == nil {
		if val != nil {
			conv := Convert(val)
			if conv != nil {
				setParent(conv, res)
				res.ColumnDefinition = conv.(*ColumnDefinition)
			}
		}
	}
	if val, err := n.ColumnPosition(); err == nil {
		if val != nil {
			conv := Convert(val)
			if conv != nil {
				setParent(conv, res)
				res.ColumnPosition = conv.(*ColumnPosition)
			}
		}
	}
	if val, err := n.FillExpression(); err == nil {
		if val != nil {
			conv := Convert(val)
			if conv != nil {
				setParent(conv, res)
				res.FillExpression = conv.(ExpressionNode)
			}
		}
	}
	if val, err := n.GetSQLForAlterAction(); err == nil {
		res.GetSQLForAlterAction = val
	}
	if val, err := n.IsIfNotExists(); err == nil {
		res.IsIfNotExists = val
	}
	if val, err := n.SingleNodeDebugString(); err == nil {
		res.SingleNodeDebugString = val
	}
	return res
}

